27	  const copy = async (e: React.MouseEvent) => {
28	    e.stopPropagation();
29	    await navigator.clipboard.writeText(value);
30	    setCopied(true);
31	    setTimeout(() => setCopied(false), 1500);
32	  };
33	  return (
34	    <Button variant="ghost" size="icon" className="h-5 w-5 shrink-0 opacity-0 group-hover:opacity-100 transition-opacity ml-1" onClick={copy}>
35	      {copied ? <Check className="h-3 w-3 text-[hsl(var(--success))]" /> : <Copy className="h-3 w-3" />}
36	    </Button>
37	  );
38	}
