40	function formatSize(bytes: number | null): string {
41	  if (!bytes) return "—";
42	  if (bytes < 1024) return `${bytes} B`;
43	  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(0)} KB`;
44	  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
45	}
